INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L004$$, 2026, $$The Civil Air Patrol (CAP) is a Congressionally chartered non-profit corporation that serves as the Auxiliary of the Air Force. CAP uses federally provided resources to provide assistance requested by the DoD,
 federal, state or local government authorities and non-governmental organizations (NGOs) to perform emergency or non-emergency public purpose missions and activities.

 Pursuant to US Code (Title 10 & 36) the purpose of CAP Corporation is to encourage and aid citizens of the US in contributing their efforts, services, and resources in developing aviation and in maintaining air
 supremacy; and to encourage and develop, by example, the voluntary contribution of private citizens to the public welfare.

 Vehicle procurements enable the Civil Air Patrol (CAP) to provide rapid deployment of emergency essential ground teams who are capable of providing critical communications and humanitarian support during
 national emergencies and disasters.

 CAP's procurement processes/standards are described in Department of Defense Grant & Agreement Regulations.
 Program element associated with this P-1 Line is: 0901223F

 Justification:
 FY26 funding covers the procurement of vehicles. CAP maintains a vehicle fleet of approximately 1,060 vehicles for 58K+ members. CAP provides critical communication and transportation for ground teams
 who support 90% of the Air Force's search and rescue (SAR) missions in accordance with the National SAR Plan, disaster relief activities, and ground teams. Vehicles also provide transportation for over 26,000
 CAP cadets to support the execution of Aerospace Education and Cadet Program missions as directed by 36 U.S.C Section 403, 10 U.S.C. Section 9442. These programs encourage and develop the voluntary
 contribution of private citizens to the public welfare focusing on the core values of Integrity, Volunteer Service, Excellence and Respect.

 42% of CAP's vehicle fleet exceeds the average Air Force vehicle age. Vehicle procurement costs have increased nearly 200% since CAP initial baseline was established in 2006.

 Vehicle type and quantities may change in execution year due to market availability, cost changes, mission requirements, additional funding, and needs of the organization.

 AF central procurement processes are not applicable.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":4,"src_title":"Cap Vehicles","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 49, 49, $$6c7b432d57039122$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L002$$, 2026, $$Passenger Carrying Vehicles includes the procurement of sedans, law enforcement sedans, ambulances, armored sedans, small buses, transit buses, large buses, intra-city motorcoach, and work buses. These
 vehicles are general in nature, but they fulfill unique and distinct needs commensurate with their design.

 Sedans are available in compact, mid-size, and large, and are used to support a variety of functions and missions at all levels of the Air Force. A portion of these sedans is dedicated for use by the Office of
 Special Investigations (OSI).

 Law Enforcement Sedans (LE Sedans) come equipped with a heavy-duty component package for law enforcement and security missions. Security forces personnel use this type of vehicle for emergency
 response, traffic control, patrol duties, and base security operations.

 Ambulances include both bus ambulances and modular ambulances used for medical evacuation operations. The bus ambulance is a 44-passenger bus converted to accommodate massive patient transport for
 medical emergency situations and humanitarian/disaster relief operations. The modular models are standard commercial ambulances available in 4x2 and 4x4 configurations. They are used for the movement of
 patients under field conditions, aircraft crash rescue operations, and routine transportation of patients to and from medical facilities.

 Buses include a variety of commercial vehicles that support a broad range of mass transit requirements. Bus sizes range from the 16-passenger shuttle bus to the 52-passenger bus. These vehicles support Air
 Education and Training Command (AETC) training units, Air Force band organizations, protocol offices, and several other missions.

 FIAR Compliance Statement:
 - "This requirement (or modification) supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

 Funding for this exhibit contained in PEs: 0207597F, 0502831F, 0507831F, 0702831F, 0202834F$$, $$$$, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":2,"src_title":"Passenger Carrying Vehicles","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 41, 41, $$7031dafdaeb8a3cb$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
