INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L010$$, 2026, $$This program includes various material handling vehicles with an individual item procurement value of less than 5M. These vehicles consist of Forklifts, Container Handlers, Baggage Conveyors, Warehouse
 Tugs and Warehouse Cranes critical to Depot and Base Supply Operations.

 Locomotive procurement is accomplished on an as needed basis to assist in DoD's mission to replace the ones nearing end of service and to modernize the aging railroad infrastructure.

 FIAR Compliance Statement:
 - This requirement (or modification) supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

 **Funding for this exhibit contained in PEs: 0207142F, 0207430F, 0207597F, 0208028F, 0507831F, 0702831F, 044011F, 0502831F, and 0202834F.$$, $$$$, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":10,"src_title":"Materials Handling Vehicles","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 83, 83, $$65892cc6c10d00b4$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1109_L042$$, 2026, $$The Family of Small Unmanned Aircraft Systems (FoSUAS), formerly Small Unit Remote Scouting System (SURSS), is a Commandant of the Marine Corps Force Modernization initiative. FoSUAS consists
 of Short Range Tactical (SRT), Medium Range Tactical (MRT), and Long Range Tactical (LRT) systems. The FoSUAS program provides weaponized and non-weaponized Small Unmanned Aircraft Systems
 (SUAS) for battalion/company/detachment level units with scalable airborne Reconnaissance, Surveillance, and Target Acquisition (RSTA) capabilities to aid in detecting, identifying, engaging, and/or avoiding
 enemy units. Although Force Modernization prioritizes LRT capabilities, the requirements for SRT and MRT systems remain to minimize operational risk and improve operational flexibility in asset allocation
 that maximizes economy of force across the conflict continuum. FoSUAS meets the validated operational requirements delineated in the Family of Tactical Unmanned Aircraft Systems (FoTUAS) Capability
 Description Document.

 SRT is a SUAS with a 5-10 km range and endurance up to 50 minutes. SRT systems address the need for situational awareness in urban and challenging terrain environments and reduce request-to-response
 timeframes for RSTA coverage.

 MRT is a SUAS with a 10-20 km range and endurance up to 4 hours. MRT provides an organic, persistent RSTA capability to company level units, Route Clearance Platoons (RCP), and Combat Logistics Patrols
 (CLP), to enhance force protection, detect Improvised Explosive Devices (IEDs), provide laser targeting/marking/range finding, and communication relay.

 LRT is a SUAS with a 20-50 km range and endurance up to 6 hours. LRT provides organic capabilities to battalion level units to satisfy Ground Combat Element (GCE) RSTA needs. LRT SUAS are currently
 deployed to conduct multi-sensor RTSA operations for Marine Forces Special Operations Command (MARSOC) and support Marine Corps fires and maneuver elements.$$, NULL, $$Exhibit P-40, Budget Line Item Justification: PB 2027 Navy                                                                                                                     Date: April 2026
