INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L040$$, 2026, $$The Wide Area Surveillance (WAS) program provides homeland defense sensors to North American Aerospace Defense Command/US Northern Command (NORAD/USNORTHCOM) for the National Capital
 Region (NCR).

 WAS consists of two advanced sensor systems, the Stateside Affordable Radar System (STARS) and Scorpion. Based upon existing technological capabilities, WAS detects/tracks low, slow and other
 asymmetrical threats in the airspace and meets the user needs of sensing stressing airborne targets in complex environments with affordable sensors. The sensor outputs are incorporated into the Battle Control
 Systems-Fixed (BCS-F) air picture and utilized as the NORAD/USNORTHCOM Command and Control (C2) air surveillance system of record.

 The WAS strategy is an acquisition approach for full capability to produce and field highly capable and sustainable advanced sensors in the NCR. In FY26, the Air Force plans to award WAS Production Contract
 efforts for both STARS and the Scorpion systems, as well as perform a technical refresh of fielded sites. In FY26, the Air Force continues to procure replenishment spares and repair parts.

 The FY 2026 request was reduced by $0.109 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222,
 "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative

 Some aspects of the WAS program are classified and information will be provided on a need-to-know basis.

 Funding for this exhibit is contained in PE 0604445F, Wide Area Surveillance.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":40,"src_title":"Wide Area Surveillance (WAS)","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 453, 453, $$4d2039746a41bc43$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L050_v21$$, 2026, $$The Combat Survivor Evader Locator (CSEL) System provides aircrews with end-to-end global satellite secure emergency communication capability during combat and peace-time flying operations. CSEL
 provides a hand held radio as part of the mandatory aircrew survival gear. CSEL is a joint program (Air Force, Army, Navy, and US Marine Corps) and is the DoD program of record for personnel recovery
 survival radios. CSEL supports four of five Personnel Mission Phases: Report, Locate, Support, and Recover.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"title_fuzzy_same_ba","rapidfuzz_score":100.0,"src_li":58,"src_title":"Combat Survivor Evader Locater","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 587, 587, $$b0c74202e1c78363$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L052_v21$$, 2026, $$Overseas Operations Costs (OOC) funds this requirement in FY2026.

 PE 0102325F Atmospheric Early Warning System (AEWS) - Joint Surveillance System (JSS)
 Funding provides procurement and installation of aging AN/FPS-117 radomes supporting the AEWS JSS.
 The AEWS provides continuous aircraft and cruise missile early warning against possible threats, Specific aircraft data position, detection from low-mid-high-altitude targets, Identification Friend or Foe (IFF) in
 support of Homeland Defense, PACOM, USNORTHCOM, NORAD and FAA missions. Radars are remotely monitored & controlled, Unattended/minimally attended. AEWS Program provides sustainment support
 for AN/FPS-117 Long Range Radar (250 NM range/100k alt) & AN/FPS-124 Short Range Radar (70 NM range/15k alt) systems to maintain the defense command and control for Alaska, Canada and Hawaii.

 PE 0102412F Atmospheric Early Warning System (AEWS) - North Warning System (NWS)
 Funding provides replacement of aging AN/FPS-117 and AN/FPS-124 radomes supporting the AEWS NWS.
 The AEWS provides continuous aircraft and cruise missile early warning against possible threats, Specific aircraft data position, detection from low-mid-high-altitude targets, Identification Friend or Foe (IFF) in
 support of Homeland Defense, PACOM, USNORTHCOM, NORAD and FAA missions. Radars are remotely monitored & controlled, Unattended/minimally attended. AEWS Program provides sustainment support
 for AN/FPS-117 Long Range Radar (250 NM range/100k alt) & AN/FPS-124 Short Range Radar (70 NM range/15k alt) systems to maintain the defense command and control for Alaska, Canada and Hawaii.

 PE 0207439F Electronic Warfare Integrated Reprogramming (EWIR)
 DISTRIBUTED MISSION OPERATIONS AND THREAT CHANGE ANALYSIS: New start. Conducted by the 453rd Electronic Warfare Squadron (453 EWS), EWIR provides analytical capabilities and reachback
 support for DoD acquisition , planning and mission execution activities. These capabilities ensure electromagnetic warfare (EW) systems and integrated combat platforms correctly recognize and respond
 to enemy, friendly and noncombatant systems operating within the electromagnetic environment. The effort includes funds used to procure specialized information technology systems used to identify
 electromagnetic spectrum emitter changes that impact combat defensive and electronic warfare systems and to conduct detailed analyses in support of operational mission planning, tactics, techniques and
 procedures (TTP) development, acquisition and test and evaluation. These analyses provide the means to understand the performance of their systems in hostile environments, directly impacting the survivability
 of combat-coded USAF aircraft and aircrews.

 PE 0208535F Collateral Equipment - Tactical Air Forces
 Collateral Equipment - Tactical Air Forces PE 0208535F/EIC FP15:$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"title_fuzzy_same_ba","rapidfuzz_score":100.0,"src_li":61,"src_title":"Base Comm Infrastructure","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 607, 607, $$b5b601f78a586526$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L053$$, 2026, $$PE 0201122F US Central Command (USCENTCOM) COMMUNICATIONS

 USCENTCOM directs and enables military operations and activities with allies and partners to increase regional security and stability in support of enduring U.S interests focusing on deterring Iran, and
 countering violent extremist organizations, competing strategically. The Middle East is an area facing ongoing challenges from regional instability and violent extremists, making USCENTCOM's mission essential
 to mitigating Direct War Enduring Costs (DWEC).

 To effectively execute this mission across such a vast geographical expanse, HQ USCENTCOM relies heavily on robust Command, Control, Communications, and Computer (C4) systems. These systems are
 crucial for achieving full-spectrum information superiority.

 Procurement funding for PE 0201122F focuses on upgrading USCENTCOM's Command and Control (C2) Systems to maintain this critical information advantage. This includes replacing end-of-life C2 systems
 (thin clients, servers, etc.), Joint Information Environment (JIE) infrastructure, and classified and unclassified voice, data, and video dissemination systems. A key component of this upgrade involves modernizing
 Storage Area Network (SAN) infrastructure and bolstering mission partner networks. This includes, but is not limited to, the CENTCOM Partner Network (CPN), CENTCOM Partner Network Episodic (CPN-X),
 and Mission Partner Environment Information System (MPE-IS). These secure networks facilitate bilateral and multilateral information sharing up to the SECRET RELEASABLE level with coalition partners.

 To further enhance C4 capabilities, procurement funding will also transition USCENTCOM's communication architecture to the Command's Collaborative Partner Environment (CPE). The CPE provides seamless
 access to data and applications across multiple devices and networks, directly enabling USCENTCOM's C2 capabilities and supports the accelerated decision-making and targeting cycles envisioned by the
 Combined Joint All Domain Command and Control (CJADC2) concepts.

 Additionally, procurement funding will assist in USCENTCOM procuring land-based spectrum monitoring nodes that capture (blue, gray, red) radio signal to enable near-real time awareness of the
 Electromagnetic operational environment (EMOE) to enable freedom of maneuver in the Electromagnetic spectrum (EMS). Ultimately, this capability will prevent Electromagnetic interference (EMI) incidents,
 enable validation of EMS usage and availability, and support Predeployment Site Survey (PDSS) efforts.

 Lastly by receiving procurement funding, USCENTCOM Command & Control, Communications and Computers System Directorate (CCJ6) can address critical data storage requirements. In addition, it will
 support maximum data storage capacity for headquarter war records collection and provide an Uninterrupted Power Supply (UPS) for the command's collateral classified and unclassified data networks.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":53,"src_title":"USCENTCOM","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 537, 537, $$3dc0d4e9f470fef9$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L053_v21$$, 2026, $$PE 0102412F Atmospheric Early Warning System (AEWS) of systems.

