INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L055$$, 2026, $$The Consolidated Space Operations Facility (CSOF) is a National Space Defense Center, which is an operational arm of USSPACECOM operations. The CSOF will be a two-story 175,823 square foot facility
 that will be constructed within the restricted area of Schriever SFB, CO. It is an approved FY20 Military Construction (MILCON) project that will house 560 personnel and include a 300-seat auditorium (the largest
 on the Front Range), dining facility, 1,300 square foot entry control facility (ECF), and a 335 vehicle parking lot. The CSOF shall provide a highly reliable facility to support the missions of the USSPACECOM
 Enterprise, including the National Space Defense Center (NSDC) and the Combined Joint Force Space Component Commander (CJFSCC). It will house current and future primary and alternate Space C2
 systems and provide C2 data to USSPACECOM. It will provide the environment to enable the development of future Space C2 systems and be the prototyping and integration location for USSPACECOM
 operations centers. Additionally, it will also provide isolated environments for modeling and simulation and as well as a cyber terrain range. The facility will be a critical component of the USSPACECOM C2
 Space Warfighting Terrain to include CSOF mission systems data feeding and establishing the USSPACECOM JOC with C2 data the enables space fires and C2.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":55,"src_title":"USSPACECOM","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 551, 551, $$cbd8edb7ac6709f9$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3080_L061$$, 2026, $$Overseas Operations Costs (OOC) funds this requirement in FY2026.

 PE 0102325F Atmospheric Early Warning System (AEWS) - Joint Surveillance System (JSS)
 Funding provides procurement and installation of aging AN/FPS-117 radomes supporting the AEWS JSS.
 The AEWS provides continuous aircraft and cruise missile early warning against possible threats, Specific aircraft data position, detection from low-mid-high-altitude targets, Identification Friend or Foe (IFF) in
 support of Homeland Defense, PACOM, USNORTHCOM, NORAD and FAA missions. Radars are remotely monitored & controlled, Unattended/minimally attended. AEWS Program provides sustainment support
 for AN/FPS-117 Long Range Radar (250 NM range/100k alt) & AN/FPS-124 Short Range Radar (70 NM range/15k alt) systems to maintain the defense command and control for Alaska, Canada and Hawaii.

 PE 0102412F Atmospheric Early Warning System (AEWS) - North Warning System (NWS)
 Funding provides replacement of aging AN/FPS-117 and AN/FPS-124 radomes supporting the AEWS NWS.
 The AEWS provides continuous aircraft and cruise missile early warning against possible threats, Specific aircraft data position, detection from low-mid-high-altitude targets, Identification Friend or Foe (IFF) in
 support of Homeland Defense, PACOM, USNORTHCOM, NORAD and FAA missions. Radars are remotely monitored & controlled, Unattended/minimally attended. AEWS Program provides sustainment support
 for AN/FPS-117 Long Range Radar (250 NM range/100k alt) & AN/FPS-124 Short Range Radar (70 NM range/15k alt) systems to maintain the defense command and control for Alaska, Canada and Hawaii.

 PE 0207439F Electronic Warfare Integrated Reprogramming (EWIR)
 DISTRIBUTED MISSION OPERATIONS AND THREAT CHANGE ANALYSIS: New start. Conducted by the 453rd Electronic Warfare Squadron (453 EWS), EWIR provides analytical capabilities and reachback
 support for DoD acquisition , planning and mission execution activities. These capabilities ensure electromagnetic warfare (EW) systems and integrated combat platforms correctly recognize and respond
 to enemy, friendly and noncombatant systems operating within the electromagnetic environment. The effort includes funds used to procure specialized information technology systems used to identify
 electromagnetic spectrum emitter changes that impact combat defensive and electronic warfare systems and to conduct detailed analyses in support of operational mission planning, tactics, techniques and
 procedures (TTP) development, acquisition and test and evaluation. These analyses provide the means to understand the performance of their systems in hostile environments, directly impacting the survivability
 of combat-coded USAF aircraft and aircrews.

 PE 0208535F Collateral Equipment - Tactical Air Forces
 Collateral Equipment - Tactical Air Forces PE 0208535F/EIC FP15:$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":61,"src_title":"Base Comm Infrastructure","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Other Procurement.pdf$$, 607, 607, $$409dc1314e0db713$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
