INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L022$$, 2026, $$The National Security Space Launch (NSSL) program is a Major Defense Acquisition Program (MDAP) Acquisition Category (ACAT) 1C program that acquires launch services to provide critical space support to
 satisfy Department of Defense (DoD) warfighter, national security, and other United States Government (USG) space lift missions. The NSSL program will leverage USG inter-agency and commercial cooperation
 by utilizing the total launch vehicle performance and maximizing on-orbit opportunities that will expedite delivery of critical capabilities. The NSSL program provides satellite delivery to specific orbits through
 certified Launch Vehicle (LV) providers.

 NSSL procures launch services and is not a weapon system. The program provides launch capacity for the Government National Launch Forecast (NLF) requirements, but does not take ownership of any
 specific launch hardware. This program does not require and does not include advance procurement or initial spares. Flyaway Unit Cost is not applicable and Weapon System Unit Cost are not representative
 due to the mix of vehicles in the program. The requirements for NSSL launch services are derived from multiple spacecraft requirements. The Space Force procurement satisfies National Security Space (NSS)
 unique capabilities for NSS requirements that are typically not addressed by the commercial market. "To Complete" projections include only known requirements at this time.

 Beginning in FY 2025, the Space Force will procure launch services to deliver National Security Space (NSS) missions via the Phase 3 contracts. NSSL Phase 3 will utilize a dual-lane approach to meet
 warfighter launch requirements, add a third launch provider, provide maximum competitive opportunities to industry, expand mission assurance options, and to allow the Government to take advantage of
 emerging and innovative launch capabilities. The dual-lane procurement approach consists of Lane 1, where launch services for risk tolerant missions will be procured from diverse launch service providers with
 annual on-ramping; and Lane 2 where launch services for specified missions will be procured from 3 fully certified systems for the nation's most critical payloads.

 The Space Force, National Reconnaissance Office (NRO), and the National Aeronautics and Space Administration (NASA) have a coordinated strategy for certification of New Entrants to launch payloads in
 support of NSS and other USG requirements. The Space Force continues to actively work with potential New Entrants to reliably meet NSS requirements. The Government may award early integration contracts
 to ensure each potential offeror's launch system is compatible with the intended payload. The Space Force's intent is to compete as much as possible all launch service procurements where more than one
 certified provider can service the required orbit.

 This requirement (or modification) supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":22,"src_title":"National Security Space Launch","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 117, 117, $$a6142df5f5853df6$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1611_L007$$, 2026, $$CANES will provide the Navy tactical/non-tactical information environment and infrastructure necessary to enable hosting, extended services reach-back and reach-forward, and relay functions. These
 capabilities will support real time and non-real time tactical/non-tactical edge connected, connectionless, and ad-hoc voice, video and data information exchange requirements. CANES replace and modernize
 afloat networks with hardware, software and enterprise services infrastructure to enable information warfare from and within the tactical domain. CANES provides complete infrastructure inclusive of hardware,
 software, processing, storage and end user devices for Unclassified, Coalition, Secret and Sensitive Compartmented Information (SCI) enclaves for all basic network services to Navy surface combatants,
 submarines and maritime operations centers. The POR CVN 79 is Increment 1.2 and CVN 80 is Increment 2.0.

