INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L026$$, 2026, $$The Space Development Agency (SDA), established in 2019, has a mission that begins and ends with the war-fighter. SDA orchestrates the development, fielding, and operation of the Department of Defense's
 (DoD's) future threat-driven Proliferated Warfighter Space Architecture (PWSA) and uses novel approaches to accelerate the delivery of military space capabilities necessary to ensure U.S. technological and
 military advantage in space for national defense. SDA will deliver capabilities to joint war-fighting forces in two-year tranches. SDA began to procure launch services for the PWSA starting in Fiscal Year (FY)
 2022 for data transport and resilient missile warning/ missile tracking (MW/MT) capabilities provided by Tranche 1 and beyond.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":26,"src_title":"Space Development Agency Launch","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 133, 133, $$3fff340669f57107$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L027$$, 2026, $$The Air Force created the Space Digital Integrated Network (SDIN) in the 1980's as the Air Force Space Command (AFSPC) Space Defense Interface Network. While it was built to support communication
 between Missile Warning/Missile Track (MW/MT) sensors and Command and Control (C2) nodes to support nuclear deterrence and missile defense of the homeland, it has grown to support every Space Force
 mission area with connections to almost all Space Force operating locations. This includes Space Domain Awareness (SDA) sensors, MILSTAR Family of Advanced Beyond Line-of-Sight Terminals (FAB-T)
 communications, Space Based Infrared System (SBIRS) ground segment communications, intra-base and inter-base communication between SOCs and other force elements, Defense Red Switch Network
 (DRSN) long local communications, Land Mobile Radios, and more.

 Justification:
 This program is a new start.

 This program is an FY 2026 New Start.

 Space Digital Integrated Network (SDIN) - Modernization: The Air Force modernized some of legacy 1980's SDIN hardware in 2012 to mitigate obsolescence, but some of the equipment is once again nearing
 end of life. The Space Force needs to modernize the network technology to ensure continuity of operations. Starting in FY26, the Space Force will perform architectural analysis, hardware procurement,
 integration, and installation activities to modernize this critical network.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":27,"src_title":"Space Digital Integrated Network (SDIN)","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 137, 137, $$6a0eeccb6cf4cac3$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L027_v23$$, 2026, $$The Air Force created the Space Digital Integrated Network (SDIN) in the 1980's as the Air Force Space Command (AFSPC) Space Defense Interface Network. While it was built to support communication
 between Missile Warning/Missile Track (MW/MT) sensors and Command and Control (C2) nodes to support nuclear deterrence and missile defense of the homeland, it has grown to support every Space Force
 mission area with connections to almost all Space Force operating locations. This includes Space Domain Awareness (SDA) sensors, MILSTAR Family of Advanced Beyond Line-of-Sight Terminals (FAB-T)
 communications, Space Based Infrared System (SBIRS) ground segment communications, intra-base and inter-base communication between SOCs and other force elements, Defense Red Switch Network
 (DRSN) long local communications, Land Mobile Radios, and more.

 Justification:
 This program is a new start.

 This program is an FY 2026 New Start.

 Space Digital Integrated Network (SDIN) - Modernization: The Air Force modernized some of legacy 1980's SDIN hardware in 2012 to mitigate obsolescence, but some of the equipment is once again nearing
 end of life. The Space Force needs to modernize the network technology to ensure continuity of operations. Starting in FY26, the Space Force will perform architectural analysis, hardware procurement,
 integration, and installation activities to modernize this critical network.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":66.7,"src_li":27,"src_title":"Space Digital Integrated Network (SDIN)","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 137, 137, $$a2543a08a6e3a35e$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L028_v23$$, 2026, $$The Spacelift Range System (SLRS), also known as the Launch and Test Range System (LTRS), provides public safety and assured access to space. LTRS operates at the Eastern Range (ER) at Patrick
 SFB/Cape Canaveral SFS, FL and the Western Range (WR) at Vandenberg SFB, CA. LTRS provides tracking, telemetry, communications, flight safety, and other capabilities to support launch of national
 security space (NSS), civil and commercial space payloads, Intercontinental and Sea Launched ballistic missile and missile defense evaluations, as well as aeronautical and guided weapon tests. LTRS ensures
 ability to meet the national launch requirement, safely support the launch cadence of ER/WR launch requirement holders and provide assured access to space for the nation. The ER and WR are designated
 as Department of Defense Major Range and Test Facility Bases (MRTFB). LTRS is comprised of 12 subsystems that together provide this capability to the ranges. The Range Safety, Command Destruct, and
 Positive Control subsystems provide the capability to destroy an errant rocket, if necessary to protect public safety. These subsystems rely on the Telemetry, Radar, and Optics subsystems to provide tracking
 data. The Weather and Surveillance subsystems allow range operators and customers to determine if conditions are safe for launch. The Communications, Data Handling, and Timing & Sequencing subsystems
 ensure critical data is expeditiously routed from remote sensors (e.g., radars, optics) to range operators and customers. Finally, the Planning and Scheduling subsystem ensures all assets are available when
 needed for a launch or test operation. The Space Force prioritizes procurement funds to transform LTRS to industry commercial standard technology and practices and ensure aging range equipment is
 modernized or replaced to meet current and projected mission requirements derived from documented Range user needs. Sustainment trends are continuously analyzed and assessed across all 12 subsystems
 and procurement funds are used to modernize the most critical mission equipment and procure replacement components. The LTRS program adopted a Digital Transformation approach to move components of
 subsystems out of sustainment into current state of practice and develop new capabilities required for modern Spaceport needs with increasingly digital infrastructure, data capabilities, and efficiencies harnessed
 through emerging technological advancements. The shift from the LTRS program into the Spaceports of the Future (SOTF) will be accomplished over the coming years through capability transformation.

 To meet evolving technological requirements and Spaceport of the Future guidance, LTRS rebalanced funding from a predominantly Procurement focused appropriation to a balanced appropriation mix of
 Procurement and RDT&E funding through a Zero Baseline Transfer FY 2025 and beyond. This realignment of appropriations ensures requirements expend against the appropriation most suited for the type
 of development work required for mission fulfillment. No requirements planned for Procurement obligations were sacrificed to achieve this shift in funding profile, but a large subset of these requirements to
 modernize Range Instrumentation and associated services were moved to the software acquisition pathway effort as core capabilities.

 1) LTRS Replenishment Spares Procurement: Provides peculiar and common support material, required re-procurement data, and interim supply support management.

 2) LTRS Support Services: FFRDC mission assurance activities ensure all twelve subsystems are compatible with mission rules and do not pose a risk to safe and cost-effective satellite launches. Funds are also
 used for Systems Engineering and Integration (SE&I) to ensure baseline documentation and modernization activities remain synchronized with the sustainment baseline.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"title_fuzzy_same_ba","rapidfuzz_score":100.0,"src_li":30,"src_title":"Spacelift Range System Space","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 175, 175, $$070554bfb042791e$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L029$$, 2026, $$Space Mods Space funding enables advanced Command and Control (C2) Battle Management, Intelligence Surveillance and Reconnaissance (ISR), and Command, Control, Communications, Computers, and
 Intelligence (C4I) systems to conduct effective predictive battle space awareness, facilitate precision attack, and compress the sensor-to-shooter kill chain. Permanent modifications are configuration changes to
 in-service systems and equipment that correct materiel or other deficiencies, or that add or delete capability. Safety modifications correct deficiencies that produce hazards to personnel, systems, or equipment.
 This budget line covers both new and on-going modification efforts for space equipment and systems. Modification installation funding is budgeted in the year the installation occurs.

 The following Program Elements are represented in this Budget Line Item:

 PE 1203165SF NAVSTAR GPS (SPACE AND CONTROL SEGMENTS):

 NAVSTAR GLOBAL POSITIONING SYSTEM (GPS) provides highly accurate time and three dimensional position and velocity information to an unlimited number of users anywhere on or above the surface of
 the earth, in any weather. This system supplies highly accurate position, velocity, timing, and United States Nuclear Detonation (NUDET) Detection System (USNDS) information to properly equipped air, land,
 sea, and space-based users worldwide. The GPS system consists of three segments: space, control, and user equipment. The Operational Control System (OCS) and the GPS Ground Antenna system are part
 of the control segment and requires modifications to replace high failure rate parts and preclude system operational degradation. Without these mods, aging and obsolete equipment will excessively degrade,
 ultimately resulting in system failure. System failure or even partial system failure will cause a loss of operational availability and the transmission of inaccurate navigation data to worldwide users, resulting in
 potential loss of life and/or operational equipment, including multi-million dollar satellites. OCS is required to operate until the Next Generation Operational Control System (OCX) transitions to operations, to
 include support for GPS III and fielding of Military GPS User Equipment (MGUE). The GPS Ground Antenna system technical refresh is required to sync and integrate with the current OCX baseline.

 PE 1203699SF Shared Early Warning System (SEWS):

 The Shared Early Warning System (SEWS) provides accurate and timely missile warning information generated by space-based infrared sensors. This information is distributed to three combatant commands
 (CCMDs)--US European Command (USEUCOM), US Central Command (USCENTCOM), and US Indo-Pacific Command (USINDOPACOM); North Atlantic Treaty Organization (NATO); and multiple foreign
 partner nations located within each of the serviced CCMDs. U.S. forces and foreign partner nations receive missile warning data via a dedicated communications network flowing from the Centralized Distribution
 Facility (CDF) at Peterson SFB, CO to secondary distribution facilities located with the CCMDs and distribution hubs located in foreign partner nation operations centers. Data segregation for the foreign nation
 partners is maintained through the use of approved cross domain solutions with unique rule sets that reflect Office of the Secretary of Defense policy regarding the dissemination of missile warning data to foreign$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":29,"src_title":"Space Mods","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 139, 139, $$64827ab447071628$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L031$$, 2026, $$Battlefield Airborne Communications Node (BACN) provides a Combatant Commander (CCDR) flexible, long-endurance, responsive airborne communications capability. BACN provides a dedicated airborne
 capability to conduct voice bridging/translation, Tactical Data Link (TDL) gateway, and TDL relay functions for beyond-line-of-sight (BLOS) data communications for the war fighter.

 Any future procurements include host platform aircraft as well as the purchase/integration of BACN payload capability, emerging capabilities, and Supplemental Type Certs (STC) and any related provisioning
 supplies. It would also provide associated systems and initial maintenance and sustainment support as well as any associated program support costs as required.

 Justification:
 No Budget Year FY26 funding requested. Funding for this exhibit contained in PE 0207238F.$$, NULL, $${"bucket":"fy26_specific_pb_v43_relaxed","method":"placeholder_or_lowscore_li","rapidfuzz_score":0.0,"src_li":31,"src_title":null,"supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196c"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 165, 165, $$4fa2fa8862408254$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L123$$, 2027, $$Advanced Expendable Countermeasures (AECM) includes ALE-70 and ALQ-260. These are multi-platform electronic warfare countermeasures that provide aircraft self-protection against air-to-air and surface-
 to-air radar guided threats. Funds procure all system components: decoys, canisters, and explosive cartridges to deploy the decoys. Funding increase from FY26 to FY27 to meet inventory objective of all
 AECMs.

 RATO: The Rocket-Assisted Take-Off (RATO) motor is a solid propellant rocket used to provide launching thrust to the Air Force Subscale Aerial Target (AFSAT) drone (BQM-167). Support items include reefing
 line cutters, igniters, and initiators. The RATO and the associated support items are single use items.

 Procurement quantities can change based on negotiated options/pricing bands and available funding, in accordance with Title 10, U.S Code Section 2308 BUY-TO-BUDGET ACQUISITION. Additional units can
 be procured based on production efficiencies or cost reductions.

 Procurements for the execution year may vary due to changes in inventory objectives. Combatant commanders' requirements for Operational Plans influence these objectives, which are updated throughout the
 year.

 Funds may be used to address production Diminishing Manufacturing Sources (DMS)/Material Shortages/Obsolescence issues through studies, bridge buys, life of type buys, supplier/parts replacement, to
 include electronic components used commercially and in short supply, qualification and lab activities to preserve future production capabilities and capacities.

 Funding for this exhibit contained in Program Elements PE 0207442F, 0305116F, and 0207040F.$$, NULL, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":100,"current_claimer_pid":"P_1506_L087","current_claimer_score":100.0,"margin":0.0,"src_li":85,"src_title":"War Consumables","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Aircraft Procurement Volume I.pdf$$, 257, 257, $$655a570713f49495$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L123$$, 2026, $$Advanced Expendable Countermeasures (AECM) includes ALE-70 and ALQ-260. These are multi-platform electronic warfare countermeasures that provide aircraft self-protection against air-to-air and surface-
 to-air radar guided threats. Funds procure all system components: decoys, canisters, and explosive cartridges to deploy the decoys.

 Items Less Than 5M: The Rocket-Assisted Take-Off (RATO) motor is a solid propellant rocket used to provide launching thrust to the Air Force Subscale Aerial Target (AFSAT) drone (BQM-167). Support items
 include reefing line cutters, igniters, and initiators. The RATO and the associated support items are single use items.

 Procurement quantities can change based on negotiated options/pricing bands and available funding, in accordance with Title 10, U.S Code Section 2308 BUY-TO-BUDGET ACQUISITION.

 Procurements for the execution year may vary due to changes in inventory objectives. Combatant commanders' requirements for Operational Plans influence these objectives, which are updated throughout the
 year.

 Funds may be used to address production Diminishing Manufacturing Sources (DMS)/Material Shortages/Obsolescence issues through studies, bridge buys, life of type buys, supplier/parts replacement, to
 include electronic components used commercially and in short supply, qualification and lab activities to preserve future production capabilities and capacities.

 The FY 2026 request was reduced by $.289 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222,
 Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.

 Funding for this exhibit contained in Program Elements PE 0207442F, 0305116F, and 0207040F.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":123,"src_title":"War Consumables","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Aircraft Procurement Vol I.pdf$$, 255, 255, $$569ad44144e85b68$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L030_v23$$, 2026, $$Initial Spares consist of reparable components, assemblies, sub-assemblies, and consumable items required as initial stock (including readiness spares package requirements) in support of space acquisition
 programs. Requirements are determined by applying established factors against the acquisition cost of the end items. The factors are based on historical data of similar equipment, employment/deployment
 concepts, production schedules, and other related information.

 Funding for this exhibit contained in PE 1203140SF (Information Systems Security Program).

 Justification:
 The FY26 budget supports initial spares for the following program: Information Systems Security Program. Procures spare components and end items enabling lifecycle sustainment COMSEC/TRANSEC
 products which support DAF, Space Force, DoD, and Intelligence Community secure communications.

 PE 1203140SF Information Systems Security Program: FY26 funding is required to supply crypto devices for space and ground nodes, used by all Services/Agencies, to meet NSA cybersecurity mandates.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"title_fuzzy_same_ba","rapidfuzz_score":100.0,"src_li":32,"src_title":"Spares and Repair Parts","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 185, 185, $$85ebcd7f520c394f$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L033$$, 2026, $$US Space Force (USSF) Non-Tactical vehicles are used to support a variety of functions and missions. System Sustainment Command (SSC) and Space Operations Command (SpOC) have mission units and
 Deltas at CONUS and OCONUS locations conducting space operations that enhance the way joint and coalition forces fight and offer decision makers military options to achieve national objectives. Space
 Training and Readiness Command (STARCOM) supports training units, protocol offices, and other training missions. USSF Vehicles consists of the following categories:

 - Passenger Carrying Vehicles includes the procurement of sedans, law enforcement sedans, ambulances, small buses, transit buses, large buses, and work buses.

 - Cargo and Utility Vehicles includes pickup trucks, trailers, semi-trailers, trucks, vans, utility trucks, maintenance, armored utility vehicles, cargo truck, truck tractors, armored sports utility vehicles, sports utility
 vehicles, and facility vehicles essential to base operations.

 - Special Purpose Vehicles includes an assortment of wreckers and refuse trucks, potable and non-potable water distribution trucks, refueling vehicles, deicers, staircase trucks, lavatory service trucks, high reach
 maintenance trucks, glycol recovery vehicles, disabled patient vehicles, high lift trucks, specialized trailers, fuel trailers, digger derrick trucks, liquid/nitrogen trucks/trailers and tow tractors.

 - Materials Handling Vehicles includes forklifts, container handlers, warehouse tugs and warehouse cranes critical to base supply operations.

 - Runway Snow Removal and Cleaning Equipment Vehicles includes front mounted brooms, multi-purpose blowers, and plows.

 - Base maintenance support vehicles includes armored loaders and dozers, water distribution trucks and heavy construction equipment (dozers, large cranes, large dump trucks, rock crushers, motorized
 scrapers, well-drilling vehicles, compactors, wheel loaders, graders, cement mixers, paving machines, excavators, sewer trucks, refuse trucks, trenches and backhoes).

 This requirement [or modification] supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":33,"src_title":"USSF Vehicles","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 187, 187, $$a4f05e15b9d9f6b0$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3022_L035$$, 2026, $$The Power Conditioning and Continuation Interfacing Equipment (PCCIE) program provides a centralized point for technical/engineering support, acquisition, fielding and sustainment of Uninterruptible Power
 Supply (UPS) systems for the Department of Air Force. UPS provide conditioned (clean) and continued (battery backup) power to protect sensitive electronic equipment/missions such as command and control
 centers, space launch and recovery facilities, space telemetry missions, intelligence gathering and transmission missions, airfield and aerodrome operations, radars, antennas, data centers and more. In short, if it
 is a critical DOD mission, an UPS provides the power conditioning and backup. UPS systems have a finite life and must be replaced at regular intervals. Many of the USSF's UPS assets have exceeded their life
 expectancy of 12-15 years.

 Uninterruptible Power Supply (UPS) systems are procured and installed under a 5-year Multi Award Contract (MAC) IDIQ, competitively awarded between four (4) Prime Contractors.

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.

 USSF funding for this exhibit is contained in PE 0207510SF$$, NULL, $${"bucket":"fy26_specific_pb_v43","method":"direct_li_with_title_overlap","rapidfuzz_score":100.0,"src_li":35,"src_title":"Power Conditioning Equipment","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196b"}$$, $$Budget J-Books/FY26/USAF/FY26 Space Force Procurement.pdf$$, 195, 195, $$41830ba546b1add9$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3010_L134$$, 2027, $$The F-15EX is a new multirole-capable fighter jet based on the 2-seat F-15QA (Qatar) configuration upgraded with advanced capabilities, including the Eagle Passive Active Warning Survivability System
 (EPAWSS) and the USAF F-15 Continuous Delivery & Integration (CD&I) Operational Flight Program (OFP) software. The F-15EX platform provides significant operational flexibility, enabling it to perform a wide
 range of mission sets with one or two aircrew. The F-15EX aircraft will be used predominantly in defensive and offensive counter-air missions at both Air National Guard (ANG) and Air Combat Command (ACC)
 operational squadrons. F-15EX will perform the Homeland Defense mission and provide Combatant Commanders (CCDR) with strike packages capable of operating in Highly Contested Environments (HCE).

 In accordance with Section 1815 of the FY 2008 National Defense Authorization Act (P.L. 110-181), this item is necessary for use by the active and reserve components of the Armed Forces for homeland
 defense missions, domestic emergency responses, and providing military support to civil authorities.

 Funding may be used to resolve Diminishing Manufacturing Sources and Material Shortages (DMSMS) and/or obsolescence issues. DMSMS activities may include, but are not limited to, bridge buys, life of type
 buys, buys to protect production schedule, and minor engineering efforts.

 Funding for this exhibit is contained in PE 0207146F. This exhibit does not include the eight (8) aircraft in Lot 1 which were funded outside this exhibit in FY 2020 (two test aircraft were purchased with RDT&E
 funds (PE 0207134F); four operationally representative test aircraft and two operational aircraft were purchased with procurement funds (F015E0, Line #3)).

 The Totals column does not include the eight (8) Lot 1 aircraft included in PEs 0207134F and 0207146F, nor the twenty one (21) Lot 7 aircraft included in the One Big Beautiful Bill reconciliation funding which
 would increase the total aircraft Procurement Quantity in this budget exhibit to 268.

 The FY 2026 spend plan amount for Aircraft Procurement includes 115,000 thousand of discretionary (qty 1) and 2,806,792 thousand of mandatory (qty 21) (reconciliation) for a total of 2,921,792 thousand (qty
 22).$$, NULL, $${"bucket":"proc_fuzzy_recovered_v43","method":"rapidfuzz_token_set_ratio","synth_score":100.0,"current_claimer_pid":"P_3010_L112","current_claimer_score":100.0,"margin":0.0,"src_li":7,"src_title":"F-15EX","applied_at":"2026-05-09T_v196"}$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Aircraft Procurement Volume I.pdf$$, 69, 69, $$d33c61079c1dce40$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_3011_L005$$, 2026, $$The following Weapon System Cost Elements are represented in this P-1 line:

 - BLU-117/MK-84 is a 2,000lb class general purpose bomb. The bomb produces blast and fragmentation effects and can be used as either an unguided high or low drag weapon. When used with a guidance kit,
 it can be employed as a precision guided bomb. The warhead is used on the GBU-10 (PAVEWAY) and Joint Direct Attack Munition (GBU-31) weapon systems. The BLU-117 can also be fuzed with proximity,
 instantaneous, or delayed fuzes to provide a variety of military effects. This item is procured through the Army Single Manager for Conventional Ammunition (SMCA). The MK-84 is a tritonal-filled variant.

 - BLU-111/MK-82 is a 500lb class general purpose bomb. The bomb produces blast and fragmentation effects and can be used as either an unguided high or low drag weapon. When used with a guidance
 kit, it can be employed as a precision guided bomb. The warhead is used on the GBU-12 (PAVEWAY) and Joint Direct Attack Munition (GBU-38/54) weapon systems. The BLU-111 can also be fuzed with
 proximity, instantaneous, or delayed fuzes to provide a variety of military effects. This item is procured through the Army Single Manager for Conventional Ammunition (SMCA). The MK-82 is a tritonal-filled
 variant.

 - BLU-140 is a 500lb Penetrator, maintaining the Outer Mold Line of the MK-82 with an internal case designed for penetration. It can be employed as a general purpose/penetrator bomb delivered in the GBU-38
 or GBU-54 configurations when combined with other Air Force commodities. BLU-140 has demonstrated improved effectiveness against certain hard targets, including multi-story and bunker-style targets,
 while increasing aircraft loadout capacity enabling more targets per sortie in the intended Areas of Responsibility (AORs). The weapon is employed by the two threshold airframes (F-16 and B-2), and objective
 airframes (any airframe compatible with the MK-82).

 - BLU-109 warhead is a 2000lb hard target penetrator bomb used against bunkers, aircraft shelters, and reinforced concrete structures. The warhead is used on the GBU-10, 24, and 27 as well as Joint Direct
 Attack Munition (JDAM) GBU-31V3 weapon systems. This item is procured through the Army Single Manager for Conventional Ammunition (SMCA). Variants are filled with tritonal or with a more Insensitive
 munitions (IM) compliant fill.

 - BLU-137 Advanced 2,000lb Penetrator (A2K) is a weapon used against bunkers, aircraft shelters, and reinforced concrete structures and is compatible with the JDAM guidance tail kit. The BLU-137/B is an
 advanced/modernized design to the BLU-109 warhead with increased reliability and survivability to prosecute increased target sets.

 - BLU-129/B 5001b Composite Case Warhead - Carbon fiber composite case for high near-field lethality to deliver 3x reduction in collateral damage. This item is procured through the Army Single Manager for$$, NULL, $${"bucket":"fy26_specific_pb_v43_relaxed","method":"placeholder_or_lowscore_li","rapidfuzz_score":22.2,"src_li":5,"src_title":"General Purpose Bombs","supersedes":"fy26_pointing_at_fy27_pb_placeholder","applied_at":"2026-05-09T_v196c"}$$, $$Budget J-Books/FY26/USAF/FY26 Air Force Ammunition Procurement.pdf$$, 43, 43, $$3c032e2d3f77caa5$$, $$2026-05-10T02:12:16.956197+00:00$$) ON CONFLICT DO NOTHING;
INSERT INTO public.proc_line_narratives (proc_line_id, fiscal_year, mission_description, justification, raw_text, source_pdf, source_page_description, source_page_amount, content_hash, ingested_at) VALUES ($$P_1611_L007$$, 2027, $$CANES will provide the Navy tactical/non-tactical information environment and infrastructure necessary to enable hosting, extended services reach-back and reach-forward, and relay functions. These
 capabilities will support real time and non-real time tactical/non-tactical edge connected, connectionless, and ad-hoc voice, video and data information exchange requirements. CANES replace and modernize
 afloat networks with hardware, software and enterprise services infrastructure to enable information warfare from and within the tactical domain. CANES provides complete infrastructure inclusive of hardware,
 software, processing, storage and end user devices for Unclassified, Coalition, Secret and Sensitive Compartmented Information (SCI) enclaves for all basic network services to Navy surface combatants,
 submarines and maritime operations centers. The POR CVN 79 is Increment 1.2 and CVN 80 is Increment 2.0.

